FROM study_plan
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted_flag = 0
LIMIT 1

SELECT

FROM study_plan
WHERE user_id = #{userId}
  AND deleted_flag = 0

ORDER BY plan_date DESC, created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

mapper.update:
UPDATE study_plan
SET deleted_flag = 1,
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted_flag = 0

UPDATE study_plan
